FUNCTION CalculateRiskExposure(risks[])
 // Input: Array of risks with probability and monetary impact
 totalExposure = 0
 contingencyBudget = 0

 FOR EACH risk IN risks DO
 // Convert probability to decimal
 probDecimal = risk.probability / 100

 // Calculate EMV (Expected Monetary Value)
 emv = probDecimal * risk.monetaryImpact

 totalExposure = totalExposure + emv

 OUTPUT risk.name, "EMV: $", emv
 ENDFOR

 // Contingency budget = sum of all EMVs
 contingencyBudget = totalExposure

 RETURN totalExposure, contingencyBudget
END FUNCTION

// Example:
// Risk A: 30% chance, $20,000 impact -> EMV = $6,000
// Risk B: 20% chance, $15,000 impact -> EMV = $3,000
// Total Exposure = $9,000
